param([Parameter(Mandatory)][string]$ManifestPath,[Parameter(Mandatory)][string]$ConfirmationPath,[switch]$PassThru)
$ErrorActionPreference='Stop';$manifest=Get-Content $ManifestPath -Raw -Encoding UTF8|ConvertFrom-Json;$confirmation=Get-Content $ConfirmationPath -Raw -Encoding UTF8|ConvertFrom-Json;$missing=[System.Collections.Generic.List[string]]::new()
foreach($grant in @($manifest.participant_grant_ids)){if(@($confirmation.grants|Where-Object{[string]$_.grant_id-eq[string]$grant-and[string]$_.status-eq'revoked'}).Count-ne1){[void]$missing.Add("grant:$grant")}}
foreach($session in @($manifest.direct_mcp_session_refs)){if(@($confirmation.direct_mcp_sessions|Where-Object{[string]$_.session_ref-eq[string]$session-and[string]$_.status-eq'revoked'}).Count-ne1){[void]$missing.Add("session:$session")}}
$complete=$missing.Count-eq0;$result=[ordered]@{status=if($complete){'revocation_confirmed'}else{'frozen_pending_revocation'};collaboration_id=$manifest.collaboration_id;missing_confirmations=@($missing);next_action_authorized=$false;artifacts_mutated=$false;audit_preserved=$true;external_calls=$false};if($PassThru){$result|ConvertTo-Json -Depth 6}else{[pscustomobject]$result|Format-List};if(-not$complete){exit 3}
